# Step 1: Import PySpark and Initialize SparkSession
from pyspark.sql import SparkSession
import kagglehub
import numpy as np
import pandas as pd

path = kagglehub.dataset_download("elemento/nyc-yellow-taxi-trip-data")
dataset1 = pd.read_csv(f"{path}/yellow_tripdata_2016-01.csv")

dataset1.to_parquet("nyc_taxi_paraquet.parquet", index=False)

dataset1.head()

dataset1.shape

spark = SparkSession.builder.appName("NycTaxi").master("local[*]").getOrCreate()

df = spark.read.parquet("/content/nyc_taxi_paraquet.parquet")

df.printSchema()

df.show(5)

df.columns

df.rdd.getNumPartitions()

result_df = df.filter(df['fare_amount'] > 10).groupby('payment_type').count()

result_df.show()

# 1 Credit card
# 2 Cash
# 3 No charge
# 4 Dispute

result_df.explain()

result_df.show()

# mode="simple" → very brief plan
# mode="extended" → more details
# mode="formatted" → easier to read
# mode="cost" → includes cost metrics

result_df.explain(mode="extended")

result_df.explain(True)

repartitioned_df = result_df.repartition(10)
print("Partitions after repartition:", repartitioned_df.rdd.getNumPartitions())

print("Total rows after transformation:", repartitioned_df.count())

repartitioned_df.show()

# Trips with more than 2 passengers
df_filtered = df.filter(df['passenger_count'] > 2)
df_filtered.show(5)
print("Filtered rows:", df_filtered.count())

# Count trips per payment type
payment_counts = df.groupBy('payment_type').count()
payment_counts.show()

# Total fare per vendor

# 1 Creative Mobile Technologies
# 2 VeriFone Inc.

vendor_fares = df.groupBy('VendorID').sum('fare_amount')
vendor_fares.show()

from pyspark.sql.functions import hour

# Trips by pickup hour
df_with_hour = df.withColumn('pickup_hour', hour(df['tpep_pickup_datetime']))
df_with_hour.groupBy('pickup_hour').count().orderBy('pickup_hour').show(24)

# Simple stats
df.describe(['trip_distance', 'fare_amount', 'tip_amount', 'total_amount']).show()

# Max trip distance
df.agg({'trip_distance':'max'}).show()

